SELECT id, company_name, company_slug, business_number, address, address_detail, created_at, updated_at
FROM admin_agencies
WHERE business_number = #{businessNumber}

SELECT id, company_name, company_slug, business_number, address, address_detail, created_at, updated_at
FROM admin_agencies
WHERE company_slug = #{companySlug}

SELECT EXISTS(
    SELECT 1 FROM admin_agencies WHERE company_slug = #{companySlug}
)

SELECT id, company_name, company_slug, business_number, address, address_detail, created_at, updated_at
FROM admin_agencies
WHERE id = #{id}
